async (params, browser) => {
  // Search Google Maps
  await browser.open(`https://www.google.com/maps/search/${params.query}`)

  // Wait for results
  await browser.waitForSelector('[role=\'feed\']', 15000)

  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ selector: '[role=\'feed\']', direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll more
  await browser.scroll({ selector: '[role=\'feed\']', direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Export all results
  const export_data = await browser.evaluate(`const results = []; const feed = document.querySelector('[role="feed"]'); if (!feed) return { result_count: 0, results: [] }; const items = feed.querySelectorAll('a.hfpxzc, div[jsaction] a[href*="/maps/place/"]'); const seen = new Set(); for (const link of items) { if (results.length >= 20) break; const href = link.href; if (seen.has(href)) continue; seen.add(href); const container = link.closest('div[jsaction]') || link.parentElement; if (!container) continue; const nameEl = container.querySelector('.qBF1Pd, .fontHeadlineSmall'); const ratingEl = container.querySelector('span[role="img"]'); const details = container.querySelectorAll('.fontBodyMedium span'); let address = '', phone = ''; for (const sp of details) { const t = sp.textContent.trim(); if (t.match(/^[\+\(]?[\d\s\-\(\)]+$/) && t.length > 6) phone = t; else if (t.length > 10 && !t.includes('\u00b7') && !t.includes('star')) address = address || t; } results.push({ name: nameEl ? nameEl.textContent.trim() : (link.getAttribute('aria-label') || 'Unknown'), rating: ratingEl ? ratingEl.getAttribute('aria-label') : '', address: address, phone: phone, url: href }); } const q = decodeURIComponent(window.location.href.split('/search/')[1] || '').split('?')[0]; return { result_count: results.length, results: results, query: q }`)

  return export_data
}
